<?php
namespace Database\Factories;
use App\Enums\JobStatus;use App\Enums\JobType;use App\Models\Job;use App\Models\User;use Illuminate\Database\Eloquent\Factories\Factory;
class JobFactory extends Factory{protected $model=Job::class;public function definition():array{return['title'=>fake()->jobTitle(),'description'=>fake()->paragraphs(2,true),'job_type'=>fake()->randomElement([JobType::DAILY,JobType::SEASONAL,JobType::PERMANENT]),'pay_rate'=>fake()->randomFloat(2,200,2000),'pay_unit'=>'day','status'=>JobStatus::OPEN,'workers_needed'=>fake()->numberBetween(1,5),'expires_at'=>now()->addDays(30),];}public function open():static{return $this->state(fn(array$a)=>['status'=>JobStatus::OPEN]);}public function closed():static{return $this->state(fn(array$a)=>['status'=>JobStatus::CLOSED]);}public function forPoster(User $poster):static{return $this->state(fn(array$a)=>['poster_id'=>$poster->id]);}public function expires():static{return $this->state(fn(array$a)=>['expires_at'=>now()->addDays(7)]);}}